#[derive(Debug, Default, Clone)]
pub struct VRInputsState {
    pub user_present_in_headset: bool,
    pub dashboard_open: bool,
    pub headset_state: Option<HeadsetState>,
    pub controllers: Vec<VRControllerState>,
    pub trackers: Vec<TrackerState>,
    pub tracking_references: Vec<TrackingReferenceState>,
    pub hands: Vec<HandState>,
    pub vive_hand_tracking: Option<ViveHandTrackingInputState>,
}

impl MemoryPackable for VRInputsState {
    fn pack(&mut self, packer: &mut MemoryPacker<'_>) {
        packer.write_packed_bools(
            self.user_present_in_headset,
            self.dashboard_open,
            false,
            false,
            false,
            false,
            false,
            false,
        );
        packer.write_object(self.headset_state.as_mut());
        packer.write_polymorphic_list(Some(&mut self.controllers[..]));
        packer.write_object_list(Some(&mut self.trackers[..]));
        packer.write_object_list(Some(&mut self.tracking_references[..]));
        packer.write_object_list(Some(&mut self.hands[..]));
        packer.write_object(self.vive_hand_tracking.as_mut());
    }
    fn unpack<P: MemoryPackerEntityPool>(&mut self, unpacker: &mut MemoryUnpacker<'_, '_, P>) {
        let __p = unpacker.read_packed_bools();
        self.user_present_in_headset = __p.bit0;
        self.dashboard_open = __p.bit1;
        self.headset_state = unpacker.read_object::<HeadsetState>();
        self.controllers = unpacker.read_polymorphic_list(decode_vr_controller_state);
        self.trackers = unpacker.read_object_list();
        self.tracking_references = unpacker.read_object_list();
        self.hands = unpacker.read_object_list();
        self.vive_hand_tracking = unpacker.read_object::<ViveHandTrackingInputState>();
    }
}

