#[derive(Clone, Copy, Debug, Default, PartialEq)]
#[repr(u8)]
pub enum LayerType {
    #[default]
    hidden = 0,
    overlay = 1,
}

impl MemoryPackable for LayerType {
    fn pack(&mut self, packer: &mut MemoryPacker<'_>) {
        packer.write(&(*self as u8));
    }
    fn unpack<P: MemoryPackerEntityPool>(&mut self, unpacker: &mut MemoryUnpacker<'_, '_, P>) {
        let raw = unpacker.read::<u8>();
        *self = match raw {
            0 => Self::hidden,
            1 => Self::overlay,
            _ => {
                warn!("invalid LayerType wire value {}; using default", raw);
                Self::hidden
            }
        };
    }
}

impl EnumRepr for LayerType {
    fn as_i32(self) -> i32 {
        self as i32
    }
    fn from_i32(i: i32) -> Self {
        match i {
            0 => Self::hidden,
            1 => Self::overlay,
            _ => {
                warn!("invalid LayerType discriminant {}; using default", i);
                Self::hidden
            }
        }
    }
}

unsafe impl Pod for LayerType {}
unsafe impl Zeroable for LayerType {}

